/* --- genom_bayes_opt_measure_connect ---------------------------------- */

genom_event
genom_bayes_opt_measure_connect(
  const char *name, genom_context self)
{
  struct genom_bayes_opt_measure_port *p =
    &self->data->self->ports.measure;
  struct genom_bayes_opt_measure_ph *ph;
  POSTER_ID pid;

  ph = genom_bayes_opt_measure_get_ph(p);

  if (!ph) return genom_no_such_inport(self);

  if (posterFind(name, &pid) != OK) {
    genom_log_warn(1, "no such port %s", name);
    return genom_no_such_outport(self);
  }
  if (posterIoctl(pid, FIO_FRESH, &(int){0}) != OK) {
    genom_log_warn(1, "cannot connect port %s", name);
    return genom_port_io(self);
  }

  ph->id = pid;
  ph->status = S_posterLib_EMPTY_POSTER;
  return genom_ok;
}


/* --- genom_bayes_opt_measure_read ------------------------------------- */

genom_event
genom_bayes_opt_measure_read(
  genom_context self)
{
  struct genom_bayes_opt_measure_port *p;
  struct genom_bayes_opt_measure_ph *ph;
  STATUS s;
  char *b;
  ssize_t max;

  p = &self->data->self->ports.measure;

  ph = genom_bayes_opt_measure_get_ph(p);
  if (!ph || !ph->id) return genom_no_such_inport(self);

  s = posterTake(ph->id, POSTER_READ);
  if (s != OK) {
    s = errnoGet();
    /* log error only once except in debug mode */
    if (ph->status != s) {
      genom_log_warn(1, "cannot access inport measure");
    } else {
      genom_log_debug("repeated error for inport measure");
    }
    ph->status = s;

    /* empty poster is OK, data() will return NULL */
    switch(s) {
      case S_posterLib_EMPTY_POSTER: return genom_ok;
    }
    return genom_port_io(self);
  }

  b = posterAddr(ph->id);
  if (b) {
    max = -1;
    s = genom_deserialize_t_or_pose_estimator_state(
      &b, &max, &(ph->buffer));
  } else s = ERROR;
  posterGive(ph->id);
  if (s) {
    ph->status = ERROR;
    genom_log_warn(0, "cannot read inport measure contents");
    return genom_serialization(self);
  }

  ph->status = 0;
  return genom_ok;
}


